import{_ as o,o as i,c as l,a0 as a}from"./chunks/framework.Dx25mwie.js";const g=JSON.parse('{"title":"Go-Spring 微信文章写作规约","description":"","frontmatter":{"head":[]},"headers":[],"relativePath":"docs/8.wechat-series/writing-style-rules.md","filePath":"docs/8.wechat-series/writing-style-rules.md"}'),d={name:"docs/8.wechat-series/writing-style-rules.md"};function c(r,e,t,p,n,s){return i(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="go-spring-微信文章写作规约" tabindex="-1">Go-Spring 微信文章写作规约 <a class="header-anchor" href="#go-spring-微信文章写作规约" aria-label="Permalink to &quot;Go-Spring 微信文章写作规约&quot;">​</a></h1><p>本规约用于约束 Go-Spring 微信正文文章的编写和改写。</p><p>目标是技术准确、主题集中、表达自然。标题优化、转场润色、示例调整和语气修改，都不能改变已有 API、配置项、生命周期顺序、优先级、错误语义和设计边界。</p><h2 id="_1-结构" tabindex="-1">1. 结构 <a class="header-anchor" href="#_1-结构" aria-label="Permalink to &quot;1. 结构&quot;">​</a></h2><ol><li>主标题使用统一格式：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Go-Spring 实战第 N 课 —— 大主题：具体能力或问题</span></span></code></pre></div><ol start="2"><li><p>开头从上一篇内容或真实工程问题进入。可以简短说明范围，但不要写成目录式预告，避免 <code>本文将介绍...</code>、<code>本篇要解决的问题有...</code>、<code>首先来看目录...</code> 这类句式。</p></li><li><p>每篇只围绕一个明确主题展开。主题可以包含多个分支或多个 API 入口，但它们必须共同回答同一个问题。</p></li><li><p>小节标题要具体，可以是对象名、能力名、阶段名或问题名。避免 <code>总结</code>、<code>小结</code>、<code>最佳实践</code>、<code>注意事项</code> 这类空泛标题。</p></li><li><p>结尾要收住当前主题，说明这块能力在 Go-Spring 整体模型里的位置。最后一个小节已经自然收束时，可以不单独加结尾段。不要写下一篇预告。</p></li></ol><h2 id="_2-内容" tabindex="-1">2. 内容 <a class="header-anchor" href="#_2-内容" aria-label="Permalink to &quot;2. 内容&quot;">​</a></h2><ol><li><p>正文必须有语义主线，不能只有 API 清单。机制型文章讲清规则和边界；概念型文章讲清普通 Go 写法的约束，以及 Go-Spring 接管和不接管的部分；API 入口型文章讲清入口解决的问题、对应语义和适用场景。</p></li><li><p>示例必须服务于当前小节。示例前后至少要说明它证明什么；示例后解释 Go-Spring 语义、适用场景或边界，不要逐行复述代码。</p></li><li><p>规则型主题可以先给总规则，再按来源、数据形态或阶段拆开解释。机制讲清后，可以补充建模、排查或选择建议，但建议必须来自前文语义。</p></li><li><p>进入 IoC、生命周期、日志、HTTP 等新体系时，可以先讲普通 Go 写法和复杂工程中的痛点，再引出 Go-Spring 抽象。不要把 Go-Spring 写成替代 Go 语言习惯的框架。</p></li><li><p>禁止使用 <code>依赖图</code>、<code>对象图</code>、<code>Bean 依赖图</code>、<code>静态对象图</code> 以及类似以“图”来组织 IoC、装配或运行期对象关系的概念。</p></li></ol><h2 id="_3-表达" tabindex="-1">3. 表达 <a class="header-anchor" href="#_3-表达" aria-label="Permalink to &quot;3. 表达&quot;">​</a></h2><ol><li><p>默认读者熟悉 Go 工程开发。不要解释 <code>struct</code>、<code>interface</code>、<code>error</code> 处理、Go module、构建部署这类基础知识。</p></li><li><p>专有名词保持稳定写法，例如 <code>Go-Spring</code>、<code>Properties</code>、<code>Path</code>、<code>Reader</code>、<code>Provider</code>、<code>Profile</code>、<code>Bean</code>、<code>IoC 容器</code>、<code>Starter</code>、<code>Map</code>、<code>Slice</code>。配置 path、结构体标签、API 名称、类型名、配置项和命令行参数使用反引号标记。</p></li><li><p>语气自然、克制、连贯。可以使用 <code>我们</code>、<code>咱们</code>、<code>大家</code>，也可以少量使用设问和口语化转场，但不能写成聊天记录、营销稿或手册条目。</p></li><li><p>讲设计取舍时，先给约束条件，再推出结论。从通用工程问题转入框架能力时，要写清这是 Go-Spring 的能力、Go-Spring 的设计，还是 Go 语言或业务代码本身的约束。</p></li><li><p>加粗、编号列表和表格都可以使用，但必须服务于核心判断、规则顺序或短枚举，不要把复杂推理塞进表格。</p></li></ol><h2 id="_4-自检" tabindex="-1">4. 自检 <a class="header-anchor" href="#_4-自检" aria-label="Permalink to &quot;4. 自检&quot;">​</a></h2><p>生成或改写后，只检查这些问题：</p><ol><li>标题是否符合统一格式。</li><li>开头是否从上一篇或工程问题进入，而不是列目录。</li><li>正文是否围绕一个主题展开，而不是只有 API 清单。</li><li>示例是否有语义解释，而不是只贴代码。</li><li>小节标题是否具体。</li><li>是否讲清 Go-Spring 的能力、边界和使用建议。</li><li>是否避免改变 API、配置项、生命周期顺序、优先级、错误语义和设计边界。</li><li>是否避免 <code>依赖图</code>、<code>对象图</code> 等图式概念。</li></ol><p>一句话要求：从真实工程复杂性出发，用自然但克制的技术文章语气，带读者看到 Go-Spring 的抽象、代码入口、适用边界、设计取舍和工程使用建议。</p>',15)])])}const _=o(d,[["render",c]]);export{g as __pageData,_ as default};
